SELECT o.OrderID, o.CustomerID, o.EmployeeID, o.OrderDate, o.RequiredDate, o.ShippedDate, o.ShipVia, o.Freight, o.ShipName, o.ShipAddress, o.ShipCity, o.ShipRegion, o.ShipPostalCode, o.ShipCountry, od.ProductID, od.UnitPrice, od.Quantity, od.Discount, p.ProductName, p.CategoryID FROM Orders o JOIN Order Details od ON o.OrderID = od.OrderID JOIN Products p ON od.ProductID = p.ProductID WHERE p.CategoryID = 3 AND o.OrderDate BETWEEN '1997-01-01' AND '1997-12-31'